-- Refresh BCI U.S. and Canada portfolio-company scorecards.
-- Mirrors the enriched records in prisma/seed-data/companies.ts for deployed databases.

UPDATE "Company" AS c
SET "name" = 'Corix District Energy',
    "updatedAt" = now()
WHERE c."name" = 'Corix Infrastructure'
  AND c."country" = 'United States / Canada'
  AND NOT EXISTS (
    SELECT 1
    FROM "Company" existing
    WHERE existing."name" = 'Corix District Energy'
      AND existing."country" = c."country"
  );

UPDATE "Company" AS c
SET "country" = 'Canada',
    "countryTags" = ARRAY['Canada'],
    "updatedAt" = now()
WHERE c."name" IN ('GCT Global Container Terminals', 'GCT Global Container Terminals Inc.')
  AND c."country" <> 'Canada'
  AND NOT EXISTS (
    SELECT 1
    FROM "Company" existing
    WHERE existing."name" = c."name"
      AND existing."country" = 'Canada'
  );

DO $migration$
DECLARE
  payload jsonb := $payload$[{"name":"Puget Energy / Puget Sound Energy","sector":"UTILITIES","subsector":"Regulated electricity and gas distribution","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Puget Energy is the holding company for Puget Sound Energy, Washington's regulated electric and gas utility. The utility serves approximately 1.2 million electric customers and 900,000 natural gas customers across a 6,000-square-mile service territory in 10 counties. Its operating model is asset-heavy and regulated, with revenue supported by utility rate structures, generation assets, transmission, distribution, and long-lived network infrastructure. AIMCo has held the investment since the 2009 take-private and increased its stake in 2018, while the current public consortium also includes Macquarie, Ontario Teachers', OMERS, BCI, and PGGM. BCI's 2024 I&RR financial statements disclose a 20.9% ownership interest in Puget Sound Energy, and BCI continued to describe PSE as one of its largest and longest-standing infrastructure investments in 2025.","companyStatus":"ACTIVE","website":null,"yearFounded":null,"headquarters":"Washington","owners":[{"investmentFirm":"AIMCo","ownershipVehicle":"n.a.","investmentYear":2009,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2009,"stake":"20.9%","status":"Active"}],"milestones":[{"date":"Feb 6, 2009","event":"Puget Holdings completed the take-private acquisition of Puget Energy through a consortium of infrastructure investors including AIMCo.","category":"ACQUISITION","sortDate":"2009-02-06"},{"date":"Mar 2018","event":"AIMCo announced that it had increased its stake in Puget Sound Energy's parent company.","category":"ACQUISITION","sortDate":"2018-03-01"},{"date":"Dec 2021","event":"Macquarie Asset Management and Ontario Teachers' signed an agreement to acquire a stake in Puget Holdings.","category":"ACQUISITION","sortDate":"2021-12-01"},{"date":"Jan 2022","event":"Macquarie and Ontario Teachers' completed the transaction and each disclosed a 15.8% ownership interest.","category":"ACQUISITION","sortDate":"2022-01-01"},{"date":"Sep 4, 2025","event":"BCI published an investment insight describing Puget Sound Energy as one of BCI's largest and longest-standing infrastructure investments.","category":"OTHER","sortDate":"2025-09-04"}],"management":[],"sources":[{"label":"Aimco — Puget Energy / Puget Sound Energy","url":"https://www.aimco.ca/insights/aimco-increases-stake-in-puget-sound-energy","type":"ARTICLE","purpose":"SUPPORTING_CONTEXT","evidenceLabel":null},{"label":"Investment date source — AIMCo — Puget Energy / Puget Sound Energy","url":"https://assets.ctfassets.net/lyt4cjmefjno/5aorUTYWwgPMIGc9cNPx9r/8518334d4637dbde57c10a376b60c10c/puget_investment.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Close date source — AIMCo — Puget Energy / Puget Sound Energy","url":"https://www.sec.gov/Archives/edgar/data/81100/000119312509027209/d8k.htm","type":"SEC_FILING","purpose":"FINANCING_FILINGS","evidenceLabel":null},{"label":"Pse — Puget Energy / Puget Sound Energy","url":"https://www.pse.com/en/about-us","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Pse — Puget Energy / Puget Sound Energy","url":"https://www.pse.com/en/Customer-Service/pse-locations-2","type":"ARTICLE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null},{"label":"Current investment source — BCI — Puget Sound Energy","url":"https://www.bci.ca/powering-the-pacific-northwest-bcis-strategic-investment-in-puget-sound-energy/","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 2009 initial investment and continuing PSE ownership context"},{"label":"Ownership interest source — BCI I&RR 2024 financial statements — Puget Sound Energy","url":"https://www.bci.ca/wp-content/uploads/2024/08/IRR-Program-FS-2024_Secured.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 20.9% ownership interest in Puget Sound Energy as of December 31, 2024"}]},{"name":"Ag Partners Capital","sector":"SOCIAL_INFRA","subsector":"Permanent-crop farmland","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Ag Partners Capital is a US agricultural investment platform focused on permanent-crop farmland. The business targets assets tied to crop categories such as almonds, pistachios, wine grapes, and citrus, serving food and agricultural supply chains rather than infrastructure end-users directly. Its operating model is asset-heavy because returns are tied to owned farmland, crop production, and long-term agricultural asset management. Public materials indicate that the platform was established in 2021 and operates through a partnership model that combines institutional capital with specialized farmland operators. Its footprint is centered on California and other US regions suited to permanent crops. BCI has described Ag Partners Capital as part of its renewable resources strategy, but public sources do not disclose the platform's full ownership structure or ownership percentages.","companyStatus":"ACTIVE","website":null,"yearFounded":2021,"headquarters":"California and other U.S. permanent-crop regions","owners":[{"investmentFirm":"BCI","ownershipVehicle":"n.a.","investmentYear":2021,"status":"Active"}],"milestones":[{"date":"2021","event":"BCI established Ag Partners Capital alongside experienced farmland investors and operators as part of its renewable-resources strategy.","category":"FINANCING","sortDate":"2021-01-01"},{"date":"2021","event":"Ag Partners Capital was founded.","category":"FOUNDING","sortDate":"2021-01-01"}],"management":[],"sources":[{"label":"Investment date source — BCI — Ag Partners Capital","url":"https://www.bci.ca/owen-martin-a-global-partnership-approach-in-renewable-resources/","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI renewable-resources partnership with Ag Partners Capital"},{"label":"Realassets — Ag Partners Capital","url":"https://realassets.ipe.com/special-reports/bci-a-global-partnership-approach-in-renewable-resources/10128357.article","type":"ARTICLE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"BCI investment inventory — Ag Partners Capital","url":"https://www.bci.ca/wp-content/uploads/2020/10/BCI-Investment-Inventory-2021-Infrastructure-Renewable-Resources.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 2021 infrastructure and renewable-resources inventory listing"}]},{"name":"Caddo Sustainable Timberlands LP","sector":"SOCIAL_INFRA","subsector":"Timberlands / sustainable forestry","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Caddo Sustainable Timberlands is a timberland platform formed to own and manage large-scale forest acreage in the US South. The business serves timber, wood-products, conservation, and land-management end markets through an asset-heavy model built around owned forestland and sustainable harvesting. Company materials describe more than 903,000 acres of timberland ownership in Texas and Louisiana, 833,000 acres in Texas, more than 30 forest-product mills served, and 100% Sustainable Forestry Initiative certification. Its offices are in Lufkin and Jasper, Texas and Atlanta, Georgia, with TTG Forestry Services providing turnkey management for Caddo timberland assets. BCI and BTG Pactual Timberland Investment Group formed the platform in 2022, and public materials do not disclose the partners' ownership percentages.","companyStatus":"ACTIVE","website":"https://www.caddolp.com/","yearFounded":2022,"headquarters":"Lufkin, Texas","owners":[{"investmentFirm":"BTG Pactual Timberland Investment Group","ownershipVehicle":"n.a.","investmentYear":2022,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2022,"status":"Active"}],"milestones":[{"date":"Feb 2026","event":"John Lock returned to Caddo as interim president while continuing as an independent director.","category":"MANAGEMENT","sortDate":"2026-02-01"},{"date":"2022","event":"Caddo began operating as a dedicated timberland ownership and management vehicle.","category":"EXPANSION","sortDate":"2022-01-01"},{"date":"2022","event":"Caddo Sustainable Timberlands LP was founded.","category":"FOUNDING","sortDate":"2022-01-01"},{"date":"Feb 14, 2022","event":"BCI and BTG Pactual Timberland Investment Group announced the creation of Caddo Sustainable Timberlands LP.","category":"FINANCING","sortDate":"2022-02-14"},{"date":"Feb 14, 2022","event":"The platform launched with approximately 772,000 acres in East Texas.","category":"OTHER","sortDate":"2022-02-14"}],"management":[{"name":"John Lock","title":"Interim President"},{"name":"Patrick Chambless","title":"Chief Financial Officer"}],"sources":[{"label":"Company profile and management source — Caddo Sustainable Timberlands LP","url":"https://www.caddolp.com/about/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"903,000 acres, offices, John Lock, and Patrick Chambless"},{"label":"Operations source — Caddo Sustainable Timberlands LP","url":"https://www.caddolp.com/sustainability/","type":"ARTICLE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null},{"label":"Investment date source — BCI — Caddo Sustainable Timberlands LP","url":"https://www.bci.ca/btg-pactual-timberland-investment-group-and-bci-create-caddo-sustainable-timberlands-lp-with-772000-acres-in-east-texas/","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI and BTG Pactual TIG created Caddo with 772,000 acres"},{"label":"Launch source — Caddo Sustainable Timberlands LP","url":"https://www.caddolp.com/2022/02/14/btg-pactual-timberland-investment-group-and-bci-create-caddo-sustainable-timberlands-lp-with-772000-acres-in-east-texas/","type":"ARTICLE","purpose":"MILESTONE_EVENT","evidenceLabel":null}]},{"name":"Cleco Corporation","sector":"UTILITIES","subsector":"Regulated electric utility","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Cleco Corporation is the holding company for Cleco Group LLC, a regulated electric utility platform serving Louisiana through Cleco Power and related generation assets. Cleco serves approximately 298,000 residential, commercial, and industrial customers in 24 Louisiana parishes, owns eight generating units with 2,676 MW of rated capacity, and remains regulated by the Louisiana Public Service Commission. The business is asset-heavy and largely regulated, with earnings supported by utility networks, generation assets, and approved tariffs. A North American investor group led by Macquarie Infrastructure and Real Assets and BCI completed the take-private acquisition in April 2016. On April 27, 2026, Stonepeak and Bernhard Capital Partners announced an agreement to acquire Cleco from Macquarie Asset Management, BCI, and Manulife Investment Management, but the transaction remained subject to customary regulatory approvals as of May 12, 2026, so the BCI holding remains active until a closing is confirmed.","companyStatus":"ACTIVE","website":"https://www.cleco.com/","yearFounded":1933,"headquarters":"Pineville, Louisiana","owners":[{"investmentFirm":"Macquarie Asset Management","ownershipVehicle":"n.a.","investmentYear":2016,"status":"Active"},{"investmentFirm":"Manulife Investment Management","ownershipVehicle":"Cleco investor consortium","investmentYear":2016,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2016,"stake":"36.9%","status":"Active"}],"milestones":[{"date":"1933","event":"Cleco's corporate history materials trace the company's founding to 1933.","category":"OTHER","sortDate":"1933-01-01"},{"date":"1933","event":"Cleco Corporation was founded.","category":"FOUNDING","sortDate":"1933-01-01"},{"date":"Oct 20, 2014","event":"Cleco announced an agreement to be acquired by an investor group led by Macquarie Infrastructure and Real Assets and BCI.","category":"ACQUISITION","sortDate":"2014-10-20"},{"date":"2016","event":"Louisiana regulatory materials disclosed the post-closing ownership interests of Macquarie, BCI, and John Hancock Financial.","category":"FINANCING","sortDate":"2016-01-01"},{"date":"Apr 13, 2016","event":"The investor group completed the acquisition of Cleco.","category":"ACQUISITION","sortDate":"2016-04-13"},{"date":"Apr 27, 2026","event":"Macquarie Asset Management, BCI, and Manulife Investment Management announced an agreement to sell Cleco Group to Stonepeak and Bernhard Capital Partners, subject to regulatory approvals.","category":"DIVESTITURE","sortDate":"2026-04-27"}],"management":[{"name":"William \"Bill\" Fontenot","title":"President and Chief Executive Officer"},{"name":"Kristin Guillory","title":"Chief Financial Officer"},{"name":"Robert Breedlove","title":"Chief Operations Officer"},{"name":"Justin \"Shane\" Hilton","title":"Chief Commercial Officer"},{"name":"Sybil Montegut","title":"Chief Administrative & Sustainability Officer"},{"name":"Andre Guillory","title":"Chief Customer Officer"}],"sources":[{"label":"Company profile source — Cleco Corporation","url":"https://www.cleco.com/about/history","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Management source — Cleco Corporation","url":"https://www.cleco.com/about/leadership-governance/executive-officers","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Current Cleco executive officers"},{"label":"Announcement date source — BCI — Cleco Corporation","url":"https://www.cleco.com/media/press-releases/detail/2014/10/20/cleco-enters-agreement-to-be-acquired-by-north-american-investor-group-led-by-macquarie-infrastructure-and-real-assets-and-british-columbia-investment-management-corporation","type":"PRESS_RELEASE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Close date source — BCI — Cleco Corporation","url":"https://www.cleco.com/media/press-releases/detail/2016/04/13/north-american-led-investor-group-completes-acquisition-of-cleco","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Ownership interest source — BCI I&RR 2024 financial statements — Cleco Corporation","url":"https://www.bci.ca/wp-content/uploads/2024/08/IRR-Program-FS-2024_Secured.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 36.9% ownership interest in Cleco Corporation as of December 31, 2024"},{"label":"Regulatory ownership source — Cleco Corporation","url":"https://lpscpubvalence.lpsc.louisiana.gov/portal/PSC/ViewFile?fileId=SnuJItgVr6k%3D","type":"ARTICLE","purpose":"FINANCING_FILINGS","evidenceLabel":null},{"label":"Pending sale source — Cleco Corporation","url":"https://www.cleco.com/media/press-releases/detail/2026/04/27/stonepeak-and-bernhard-capital-partners-to-acquire-cleco","type":"PRESS_RELEASE","purpose":"MILESTONE_EVENT","evidenceLabel":"Sale announced April 27, 2026; subject to regulatory approvals"}]},{"name":"Corix District Energy","sector":"UTILITIES","subsector":"District energy and thermal utility systems","region":"NORTH_AMERICA","country":"United States / Canada","countryTags":["United States","Canada"],"description":"Corix District Energy is a North American district-energy and utility thermal infrastructure platform that develops and operates energy systems for new developments, municipalities, institutions, campuses, and other community-scale customers. Its business is asset-heavy because value is tied to owned utility networks, central thermal plants, and long-lived energy infrastructure rather than outsourced services alone. Current company materials identify systems including Burnaby Mountain, Dockside Green, UBC Neighbourhood District Energy System, Bellingham Waterfront, Cleveland Thermal, Doyon Utilities, and Utah City. Corix's U.S. regulated water and wastewater business completed its merger with SouthWest Water to form Nexus Water Group on April 1, 2024, leaving Corix as the standalone BCI-backed district-energy platform. Corix identifies BCI as its shareholder, while current public materials do not disclose a separate ownership percentage for the post-Nexus district-energy business.","companyStatus":"ACTIVE","website":"https://www.corix.com/","yearFounded":2006,"headquarters":"Vancouver, British Columbia","owners":[{"investmentFirm":"BCI","ownershipVehicle":"n.a.","investmentYear":2006,"status":"Active"}],"milestones":[{"date":"2006","event":"BCI affiliates acquired shares of Terasen Utility Services, the predecessor to Corix Multi-Utility Services, causing BCI to indirectly control the business.","category":"ACQUISITION","sortDate":"2006-01-01"},{"date":"Oct 24, 2012","event":"BCI acquired CAI Capital Partners' interest in the Corix Group of Companies, taking effective control through an additional share acquisition.","category":"ACQUISITION","sortDate":"2012-10-24"},{"date":"Aug 26, 2022","event":"Corix entered an agreement with IIF Subway Investment L.P., SWMAC and SouthWest Water to combine its U.S. water utility business.","category":"FINANCING","sortDate":"2022-08-26"},{"date":"Apr 1, 2024","event":"Corix Infrastructure's U.S. water and wastewater business completed its merger with SouthWest Water to form Nexus Water Group.","category":"OTHER","sortDate":"2024-04-01"}],"management":[{"name":"Lisa Sparrow","title":"President & CEO"},{"name":"Travis Hickford-Kulak","title":"Chief Operating Officer (West)"},{"name":"Seth Whitney","title":"Chief Operating Officer (East)"},{"name":"Max Wang","title":"Chief Financial Officer"},{"name":"Diego Mandelbaum","title":"Chief Development Officer"},{"name":"Fan Jiang","title":"Chief Growth Officer & VP Administration"}],"sources":[{"label":"Company profile and management source — Corix District Energy","url":"https://www.corix.com/about-us/our-team/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Current Corix leadership and BCI shareholder disclosure"},{"label":"Operations source — Corix District Energy","url":"https://www.corix.com/","type":"WEBSITE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null},{"label":"BCI inventory source — Corix District Energy","url":"https://www.bci.ca/wp-content/uploads/2020/10/BCI-Investment-Inventory-2021-Infrastructure-Renewable-Resources.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Investment date source — BCI — Corix District Energy","url":"https://myutility.nexuswatergroup.com/docs/default-source/communities/communities-common/application---corix-restructuring-and-business-combination-transactions.pdf?sfvrsn=1c2b6b5d_2","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Water business separation source — Nexus Water Group","url":"https://nexuswatergroup.com/2024/04/02/nexus-water-group-press-release/","type":"ARTICLE","purpose":"MILESTONE_EVENT","evidenceLabel":"Corix U.S. water/wastewater business merged into Nexus on April 1, 2024"}]},{"name":"GCT Global Container Terminals Inc.","sector":"TRANSPORTATION","subsector":"Container terminals / ports","region":"NORTH_AMERICA","country":"Canada","countryTags":["Canada"],"description":"GCT Global Container Terminals is a marine terminal operator serving containerized trade flows through Canada's Pacific Gateway. Its customers are ocean carriers, logistics providers, railroads, truckers, and cargo owners that rely on terminal infrastructure for import, export, and intermodal flows. The business is asset-heavy and volume-linked because performance depends on terminal concessions, berths, yard capacity, cranes, rail infrastructure, and throughput levels. Current company materials identify GCT as the largest majority Canadian-owned container terminal operator on Canada's west coast, operating GCT Deltaport in Delta and GCT Vanterm in Vancouver with four berths and nearly 3.5 million TEUs of annual capacity. Ontario Teachers', IFM Investors, and BCI announced in 2018 that IFM and BCI would join Teachers as equity partners in GCT, with disclosed ownership of 37.5% Ontario Teachers', 37.5% IFM Investors, and 25% BCI.","companyStatus":"ACTIVE","website":"https://globalterminals.com/","yearFounded":1907,"headquarters":"British Columbia","owners":[{"investmentFirm":"OTPP","ownershipVehicle":"n.a.","investmentYear":2007,"stake":"37.5%","status":"Active"},{"investmentFirm":"IFM Investors","ownershipVehicle":"IFM Global Infrastructure Fund (GIF)","investmentYear":2018,"stake":"37.5%","status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2018,"stake":"25%","status":"Active"}],"milestones":[{"date":"1907","event":"Public company history materials trace GCT's origins in Vancouver to 1907.","category":"OTHER","sortDate":"1907-01-01"},{"date":"1907","event":"GCT Global Container Terminals Inc. was founded.","category":"FOUNDING","sortDate":"1907-01-01"},{"date":"Jun 7, 2018","event":"Ontario Teachers' announced that IFM Investors and BCI would join as equity partners in GCT.","category":"ACQUISITION","sortDate":"2018-06-07"},{"date":"Jun 7, 2018","event":"The transaction disclosures set ownership at 37.5% for Ontario Teachers', 37.5% for IFM, and 25% for BCI.","category":"OTHER","sortDate":"2018-06-07"}],"management":[{"name":"Eric Waltz","title":"President & Chief Executive Officer"},{"name":"Cheryl Yaremko","title":"Chief Financial Officer"},{"name":"Daniel Howell","title":"Chief Operating Officer"},{"name":"Erik Ward","title":"Chief Information Officer"},{"name":"Chris Ng","title":"Chief Commercial Officer"}],"sources":[{"label":"Company profile source — GCT Global Container Terminals Inc.","url":"https://globalterminals.com/about/about-us/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Two-terminal Port of Vancouver operator and annual capacity"},{"label":"Management source — GCT Global Container Terminals Inc.","url":"https://globalterminals.com/about/leadership/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Current GCT leadership team"},{"label":"Investment source — GCT Global Container Terminals Inc.","url":"https://globalterminals.com/ifm-investors-bci-join-ontario-teachers-equity-partners-gct-global-container-terminals-inc/","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 25%, IFM 37.5%, Ontario Teachers' 37.5%"},{"label":"Announcement date source — BCI — GCT Global Container Terminals Inc.","url":"https://www.otpp.com/en-ca/about-us/news-and-insights/2018/ifm-investors-and-bci-to-join-ontario-teachers-as-equity-partners-in-gct-global-container-terminals-inc-/","type":"PRESS_RELEASE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Operations source — GCT Global Container Terminals Inc.","url":"https://bcmarineterminals.com/global-container-terminals/","type":"ARTICLE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null}]},{"name":"InTransit BC","sector":"TRANSPORTATION","subsector":"Urban rail transit concession","region":"NORTH_AMERICA","country":"Canada","countryTags":["Canada"],"description":"InTransit BC is the concessionaire responsible for the Canada Line rapid transit system in Metro Vancouver. The system serves urban commuters, airport passengers, and local transit users through a long-term public-private partnership with TransLink. Its operating model is asset-heavy and concession-based, with value tied to long-lived rail infrastructure and contractual payments rather than merchant transportation demand alone. Public sources describe the Canada Line as an 18-kilometre system with 16 stations linking downtown Vancouver, Richmond, and Vancouver International Airport. Operations are concentrated in British Columbia under a 35-year concession that runs to 2040. BCI's pooled-fund disclosures report a 28.7% interest in InTransit BC, while full public disclosure of the remaining ownership group is limited.","companyStatus":"ACTIVE","website":null,"yearFounded":null,"headquarters":"British Columbia","owners":[{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2005,"stake":"28.7%","status":"Active"},{"investmentFirm":"CDPQ","ownershipVehicle":"n.a.","investmentYear":2005,"stake":"33.3%","status":"Active"}],"milestones":[{"date":"Jul 29, 2005","event":"InTransit BC closed the 35-year Canada Line P3 concession with the Greater Vancouver Transportation Authority; BCI invested as one of the three equity partners alongside SNC-Lavalin and CDPQ.","category":"FINANCING","sortDate":"2005-07-29"},{"date":"2009","event":"The Canada Line entered service between downtown Vancouver, Richmond, and Vancouver International Airport.","category":"EXPANSION","sortDate":"2009-01-01"},{"date":"Aug 2009","event":"TransLink's public reporting indicates the Canada Line concession commenced in August 2009.","category":"OTHER","sortDate":"2009-08-01"},{"date":"2022","event":"BCI pooled-fund financial statements disclosed a 28.7% interest in InTransit BC.","category":"FINANCING","sortDate":"2022-01-01"}],"management":[],"sources":[{"label":"Close date source — BCI — InTransit BC","url":"https://www.lexpert.ca/big-deals/ravco-intransit-bc-and-the-gvta-enter-into-p3/345743","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Close date source — CDPQ — InTransit BC","url":"https://www.lexpert.ca/big-deals/ravco-intransit-bc-and-the-gvta-enter-into-p3/345743","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Interest confirmation source — CDPQ — InTransit BC","url":"https://www.cdpqinfra.com/sites/cdpqinfrad8/files/2021-10/03-CDPQI-AAM-EN_notice_to_market.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"CDPQ 33.3% ownership interest"},{"label":"Ownership interest source — BCI — InTransit BC","url":"https://www.bci.ca/wp-content/uploads/2018/01/2022_InfrastructureRenewableResources-Pooled-Fund-Financial-Statements-1.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 28.7% ownership interest in InTransit BC"},{"label":"Translink — InTransit BC","url":"https://www.translink.ca/-/media/translink/documents/about-translink/corporate-reports/quarterly_reports/2024/2024-year-end-financial-and-performance-report.pdf","type":"PRESENTATION","purpose":"SUPPORTING_CONTEXT","evidenceLabel":null},{"label":"Translink — InTransit BC","url":"https://www.translink.ca/about-us/projects/canada-line","type":"WEBSITE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null}]},{"name":"Monterey Mushrooms","sector":"SOCIAL_INFRA","subsector":"Controlled-environment agriculture / mushrooms","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Monterey Mushrooms is a producer and marketer of fresh mushrooms and related products for grocery, foodservice, and packaged-food customers. The business operates a vertically integrated model that includes growing, harvesting, packaging, and distribution rather than a purely branded or distribution-only approach. It is asset-heavy because output depends on controlled-environment growing facilities, composting capacity, distribution infrastructure, and labor-intensive operations. Company materials state that Monterey Mushrooms produces roughly 250 million pounds of mushrooms annually, employs around 4,000 people, and operates across multiple US states and Mexico. Its principal US operations include California, Texas, Illinois, Tennessee, Florida, and Pennsylvania. European Commission merger materials in 2025 identified BCI and Paine Schwartz Partners as acquiring joint control of Monterey Mushrooms Holdings; public materials do not disclose the partners' ownership percentages.","companyStatus":"ACTIVE","website":null,"yearFounded":1971,"headquarters":"California, Texas, Illinois, Tennessee, Florida, and Pennsylvania","owners":[{"investmentFirm":"Paine Schwartz Partners","ownershipVehicle":"n.a.","investmentYear":2025,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"n.a.","investmentYear":2025,"status":"Active"}],"milestones":[{"date":"1971","event":"Company history materials indicate that Monterey Mushrooms was founded in 1971.","category":"FOUNDING","sortDate":"1971-01-01"},{"date":"Jul 22, 2025","event":"BCI and Paine Schwartz Partners submitted a European Commission merger filing for joint control of Monterey Mushrooms Holdings.","category":"ACQUISITION","sortDate":"2025-07-22"},{"date":"Aug 25, 2025","event":"The European Commission published its decision for case M.12002 covering BCI and Paine Schwartz Partners' joint control of Monterey Mushrooms Holdings.","category":"OTHER","sortDate":"2025-08-25"}],"management":[],"sources":[{"label":"Montereymushrooms — Monterey Mushrooms","url":"https://www.montereymushrooms.com/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Montereymushrooms — Monterey Mushrooms","url":"https://www.montereymushrooms.com/about-monterey-mushrooms","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Montereymushrooms — Monterey Mushrooms","url":"https://www.montereymushrooms.com/our-story-monterey-mushrooms","type":"ARTICLE","purpose":"SUPPORTING_CONTEXT","evidenceLabel":null},{"label":"Announcement date source — BCI — Monterey Mushrooms","url":"https://ec.europa.eu/competition/mergers/cases1/202535/M_12002_10733619_125_3.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Merger decision source — Monterey Mushrooms","url":"https://eur-lex.europa.eu/legal-content/EN/ALL/?uri=CELEX%3A32025M12002","type":"ARTICLE","purpose":"MILESTONE_EVENT","evidenceLabel":"European Commission case M.12002 for BCI / Paine Schwartz / Monterey Mushrooms"}]},{"name":"Mosaic Forest Management","sector":"SOCIAL_INFRA","subsector":"Timberlands management / sustainable forestry","region":"NORTH_AMERICA","country":"Canada","countryTags":["Canada"],"description":"Mosaic Forest Management is a timberlands management company overseeing large private forestlands and associated public tenures on Vancouver Island and coastal British Columbia. The platform serves timber, lumber, and broader forest-products markets through harvesting, stewardship, and land-management activities. Its operating model is asset-heavy because it manages extensive timberlands where value is tied to land quality, biological growth, harvest planning, and log sales. Company materials describe Mosaic as the manager for the TimberWest and Island Timberlands ownership interests and note a supply chain supporting roughly 2,000 employees and contractors. Operations are concentrated in British Columbia, particularly on Vancouver Island and the province's coast. Mosaic launched in 2018 as the management platform for TimberWest and Island Timberlands; BCI's 2024 I&RR financial statements disclose a 56.1% ownership interest in Mosaic LP, while public materials also identify PSP Investments as an underlying ownership partner.","companyStatus":"ACTIVE","website":null,"yearFounded":2018,"headquarters":"British Columbia","owners":[{"investmentFirm":"PSP Investments","ownershipVehicle":"n.a.","investmentYear":2018,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2018,"stake":"56.1%","status":"Active"}],"milestones":[{"date":"2018","event":"Mosaic began managing extensive private forest lands and public tenures in coastal British Columbia.","category":"OTHER","sortDate":"2018-01-01"},{"date":"2018","event":"Mosaic Forest Management was founded.","category":"FOUNDING","sortDate":"2018-01-01"},{"date":"Nov 1, 2018","event":"BCI, PSP Investments, and AIMCo-affiliated Island Timberlands investors launched Mosaic Forest Management as the management platform for TimberWest and Island Timberlands.","category":"FINANCING","sortDate":"2018-11-01"}],"management":[],"sources":[{"label":"Mosaicforests — Mosaic Forest Management","url":"https://www.mosaicforests.com/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Investment date source — BCI — Mosaic Forest Management","url":"https://www.mosaicforests.com/news-views/2018/11/mosaic-forest-management-launch-wbcjc","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Mosaicforests — Mosaic Forest Management","url":"https://www.mosaicforests.com/timberlands","type":"ARTICLE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null},{"label":"Newnavigationtwo — Mosaic Forest Management","url":"https://newnavigationtwo.squarespace.com/s/Mosaic-2024-Supply-Chain-Report.pdf","type":"PRESENTATION","purpose":"OPERATIONS_ASSETS","evidenceLabel":null},{"label":"Ownership interest source — BCI I&RR 2024 financial statements — Mosaic Forest Management","url":"https://www.bci.ca/wp-content/uploads/2024/08/IRR-Program-FS-2024_Secured.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 56.1% ownership interest in Mosaic LP as of December 31, 2024"}]},{"name":"Nexus Water Group","sector":"UTILITIES","subsector":"Water and wastewater utility","region":"NORTH_AMERICA","country":"United States / Canada","countryTags":["United States","Canada"],"description":"Nexus Water Group is a regulated water and wastewater utility platform formed through the combination of Corix Infrastructure's U.S. regulated water and wastewater business and SouthWest Water Company. The platform serves residential, commercial, and municipal utility customers through owned water distribution, wastewater collection, and treatment systems. Nexus reported at launch that it employed more than 1,300 professionals serving more than 1.3 million people across North America through over 670 water systems and over 360 wastewater systems, with local operations across 20 U.S. states and two Canadian provinces. The merger closed on April 1, 2024, and BCI's 2024 I&RR financial statements disclose a 50.0% ownership interest in Nexus Water Group Inc. Nexus announced asset-sale agreements with American Water in 2025 and California Water Service Group in 2026, but the company stated the Nevada/Oregon sale was expected to close by the end of 2026 following required regulatory approvals, so BCI's Nexus holding remains active as of May 12, 2026.","companyStatus":"ACTIVE","website":"https://nexuswatergroup.com/","yearFounded":2024,"headquarters":"Sugar Land, Texas","owners":[{"investmentFirm":"J.P. Morgan Asset Management","ownershipVehicle":"Infrastructure Investments Fund (IIF)","investmentYear":2024,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2024,"stake":"50.0%","status":"Active"}],"milestones":[{"date":"2024","event":"Nexus Water Group was founded.","category":"FOUNDING","sortDate":"2024-01-01"},{"date":"Apr 1, 2024","event":"BCI-controlled Corix Infrastructure's U.S. regulated water and wastewater business and J.P. Morgan Asset Management IIF-backed SouthWest Water completed their merger to create Nexus Water Group.","category":"ACQUISITION","sortDate":"2024-04-01"},{"date":"Apr 2, 2024","event":"Nexus Water Group formally announced the closing of the merger.","category":"OTHER","sortDate":"2024-04-02"},{"date":"May 19, 2025","event":"Nexus announced a definitive agreement to sell operations and assets in eight states to American Water.","category":"DIVESTITURE","sortDate":"2025-05-19"},{"date":"Feb 25, 2026","event":"Nexus announced an agreement to sell its Nevada and Oregon assets to California Water Service Group, with closing expected by the end of 2026 after required regulatory approvals.","category":"DIVESTITURE","sortDate":"2026-02-25"}],"management":[{"name":"Rob MacLean","title":"President & Chief Executive Officer"},{"name":"Richard Rich","title":"Chief Operating Officer"},{"name":"Alison Zimlich","title":"Chief Financial Officer"},{"name":"Jim Devine","title":"Chief Services Officer"},{"name":"Joanne Elliott","title":"Chief Human Resources Officer"},{"name":"Joseph Park","title":"Chief Legal Officer"},{"name":"Don Sudduth","title":"Chief Growth Officer"}],"sources":[{"label":"Nexuswatergroup — Nexus Water Group","url":"https://www.nexuswatergroup.com/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Management source — Nexus Water Group","url":"https://nexuswatergroup.com/our-company/executive-leadership-team/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Current Nexus executive leadership team"},{"label":"Close date source — BCI — Nexus Water Group","url":"https://nexuswatergroup.com/2024/04/02/nexus-water-group-press-release/","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"Corix and SouthWest Water merger closed April 1, 2024"},{"label":"Close date source — J.P. Morgan Asset Management — Nexus Water Group","url":"https://app.mergerlinks.com/transactions/2022-08-29-corix-infrastructure-water-and-wastewater-businesses/service-providers","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Nexuswatergroup — Nexus Water Group","url":"https://nexuswatergroup.com/2025/05/19/nexus-water-group-enters-into-a-definitive-agreement-to-sell-assets-in-eight-states-to-american-water/","type":"ARTICLE","purpose":"MILESTONE_EVENT","evidenceLabel":null},{"label":"Pending asset-sale source — Nexus Water Group","url":"https://nexuswatergroup.com/2026/02/25/nexus-water-group-agrees-to-sell-nevada-and-oregon-assets-to-california-water-service-group/","type":"PRESS_RELEASE","purpose":"MILESTONE_EVENT","evidenceLabel":"Nevada/Oregon sale announced February 25, 2026; closing expected by year-end 2026"},{"label":"Restructuring source — Nexus Water Group","url":"https://myutility.nexuswatergroup.com/docs/default-source/communities/communities-common/application---corix-restructuring-and-business-combination-transactions.pdf?sfvrsn=1c2b6b5d_2","type":"PRESENTATION","purpose":"FINANCING_FILINGS","evidenceLabel":null},{"label":"Ownership interest source — BCI I&RR 2024 financial statements — Nexus Water Group","url":"https://www.bci.ca/wp-content/uploads/2024/08/IRR-Program-FS-2024_Secured.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 50.0% ownership interest in Nexus Water Group Inc as of December 31, 2024"}]},{"name":"Northview Energy","sector":"POWER_ET","subsector":"Contracted utility-scale wind and solar","region":"NORTH_AMERICA","country":"United States / Canada","countryTags":["United States","Canada"],"description":"Northview Energy is a renewable-power platform announced by Brookfield, BCI, and Norges Bank Investment Management on March 3, 2026. The platform is intended to acquire and own contracted utility-scale solar and onshore wind assets that sell power under long-term agreements to investment-grade counterparties. Its operating model is asset-heavy and contracted, with value tied to owned generation assets and long-duration power purchase agreements rather than merchant development alone. The seed portfolio comprises 22 contracted operating solar and onshore wind assets totaling approximately 2.3 GW across six U.S. power markets, with a weighted-average remaining contract term of roughly 16 years. The partners announced equal funding and ownership by Brookfield, BCI, and Norges Bank Investment Management, plus a framework agreement for up to $1.5 billion of future equity capital for additional Brookfield-managed renewable acquisitions in the United States and Canada. Public materials stated Northview was expected to officially launch during Q2 2026 subject to required approvals and customary closing conditions.","companyStatus":"ACTIVE","website":"https://www.northviewenergy.com/","yearFounded":2026,"headquarters":"Multiple U.S. states","owners":[{"investmentFirm":"Brookfield Asset Management","ownershipVehicle":"Northview Energy platform","investmentYear":2026,"stake":"One-third / equal ownership","status":"Active"},{"investmentFirm":"Norges Bank Investment Management","ownershipVehicle":"Northview Energy platform","investmentYear":2026,"stake":"One-third / equal ownership","status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2026,"stake":"One-third / equal ownership","status":"Active"}],"milestones":[{"date":"2026","event":"Northview Energy was founded.","category":"FOUNDING","sortDate":"2026-01-01"},{"date":"Mar 3, 2026","event":"Brookfield, BCI, and Norges Bank Investment Management announced the launch of Northview Energy.","category":"FINANCING","sortDate":"2026-03-03"},{"date":"Mar 3, 2026","event":"The partners announced equal ownership among Brookfield, BCI, and Norges Bank Investment Management.","category":"FINANCING","sortDate":"2026-03-03"},{"date":"Mar 3, 2026","event":"The partners disclosed a 2.3 GW seed portfolio of 22 contracted operating renewable assets across six U.S. power markets.","category":"OTHER","sortDate":"2026-03-03"}],"management":[],"sources":[{"label":"Announcement date source — BCI — Northview Energy","url":"https://www.bci.ca/news/article/bci-norges-bank-investment-management-and-brookfield-partner-to-launch-northview-energy/","type":"PRESS_RELEASE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"Northview equally funded and owned by BCI, NBIM, and Brookfield"},{"label":"Announcement date source — Brookfield — Northview Energy","url":"https://bep.brookfield.com/press-releases/bep/bci-norges-bank-investment-management-and-brookfield-partner-launch-northview","type":"PRESS_RELEASE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Nbim — Northview Energy","url":"https://www.nbim.no/en/news-and-insights/the-press/press-releases/2026/new-investment-in-unlisted-renewable-energy-infrastructure/","type":"ARTICLE","purpose":"SUPPORTING_CONTEXT","evidenceLabel":null},{"label":"Milbank — Northview Energy","url":"https://www.milbank.com/en/news/milbank-advises-bci-on-launch-of-northview-energy.html","type":"ARTICLE","purpose":"MILESTONE_EVENT","evidenceLabel":null},{"label":"Bam — Northview Energy","url":"https://bam.brookfield.com/press-releases/bci-norges-bank-investment-management-and-brookfield-partner-launch-northview-energy","type":"ARTICLE","purpose":"MILESTONE_EVENT","evidenceLabel":null},{"label":"GlobeNewsWire - INF-2026-105 - Northview Energy","url":"https://www.globenewswire.com/news-release/2026/03/03/3248185/0/en/BCI-Norges-Bank-Investment-Management-and-Brookfield-Partner-to-Launch-Northview-Energy.html","type":"PRESS_RELEASE","purpose":"MILESTONE_EVENT","evidenceLabel":null}]},{"name":"Teays River Investments","sector":"SOCIAL_INFRA","subsector":"Agricultural investment platform","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Teays River Investments is a permanent-capital agricultural investment platform focused on assets and businesses across the food and agriculture value chain. Its activities span farmland, agribusiness, and related operating investments serving agricultural production and food distribution markets. The model is asset-heavy because returns depend on owned agricultural assets and operating businesses rather than fee-only advisory revenue. Public sources identify Carmel, Indiana as the company's headquarters and indicate a multi-state U.S. operating footprint. The company was founded in 2008 and continues to operate as a long-duration investment platform. BCI has referenced Teays River Investments in public materials about its renewable-resources partnerships, and BCI's 2024 I&RR financial statements disclose a 19.9% ownership interest in Teays River Investments LLC.","companyStatus":"ACTIVE","website":null,"yearFounded":2008,"headquarters":"Indiana and multi-state United States","owners":[{"investmentFirm":"BCI","ownershipVehicle":"n.a.","investmentYear":2021,"stake":"19.9%","status":"Active"}],"milestones":[{"date":"2008","event":"Teays River Investments was founded.","category":"FOUNDING","sortDate":"2008-01-01"},{"date":"2021","event":"BCI publicly described increasing its investment with Teays River as part of its renewable-resources strategy.","category":"FINANCING","sortDate":"2021-01-01"},{"date":"Apr 30, 2025","event":"Teays River Investments announced the appointment of Micah Vincent as president and chief executive officer.","category":"MANAGEMENT","sortDate":"2025-04-30"}],"management":[{"name":"Micah Vincent","title":"President and Chief Executive Officer"}],"sources":[{"label":"Teaysinvestments — Teays River Investments","url":"https://www.teaysinvestments.com/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Management source — Teays River Investments","url":"https://www.prnewswire.com/news-releases/teays-river-investments-names-micah-vincent-president-and-ceo-302642376.html","type":"PRESS_RELEASE","purpose":"MILESTONE_EVENT","evidenceLabel":"Micah Vincent named President and CEO on April 30, 2025"},{"label":"Investment date source — BCI — Teays River Investments","url":"https://www.bci.ca/owen-martin-a-global-partnership-approach-in-renewable-resources/","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Ownership interest source — BCI I&RR 2024 financial statements — Teays River Investments","url":"https://www.bci.ca/wp-content/uploads/2024/08/IRR-Program-FS-2024_Secured.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 19.9% ownership interest in Teays River Investments LLC as of December 31, 2024"}]},{"name":"Puget Sound Energy","sector":"UTILITIES","subsector":"Regulated electric and gas utility","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Puget Sound Energy is a regulated electric and natural gas utility serving residential, commercial, and industrial customers in Washington. Public disclosures state that the company serves about 1.2 million electric customers and nearly 900,000 natural gas customers across a 6,000-square-mile territory in 10 counties. The operating model is asset-heavy and predominantly regulated, supported by generation, transmission, and distribution assets with revenues recovered through approved tariffs. Company materials describe owned and contracted hydro, wind, solar, natural gas, biomass, and other power resources, while BCI noted in September 2025 that PSE planned to phase out all coal-based electric generation by the end of 2025 and continue adding renewable and non-emitting resources. PSE was taken private in 2009 by a long-term infrastructure consortium that included BCI, and BCI's 2024 I&RR financial statements disclose a 20.9% ownership interest in Puget Sound Energy.","companyStatus":"ACTIVE","website":null,"yearFounded":1997,"headquarters":"Washington","owners":[{"investmentFirm":"Macquarie Asset Management","ownershipVehicle":"MGIF","investmentYear":2022,"status":"Active"},{"investmentFirm":"OTPP","ownershipVehicle":"n.a.","investmentYear":2022,"status":"Active"},{"investmentFirm":"OMERS","ownershipVehicle":"n.a.","investmentYear":2018,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2009,"stake":"20.9%","status":"Active"},{"investmentFirm":"AIMCo","ownershipVehicle":"n.a.","investmentYear":2009,"status":"Active"},{"investmentFirm":"PGGM","ownershipVehicle":"n.a.","status":"Active"}],"milestones":[{"date":"1997","event":"Puget Sound Energy was founded.","category":"FOUNDING","sortDate":"1997-01-01"},{"date":"Feb 6, 2009","event":"Puget Holdings completed the take-private acquisition of Puget Energy and Puget Sound Energy with AIMCo and BCI included in the original investor consortium.","category":"ACQUISITION","sortDate":"2009-02-06"},{"date":"Aug 2018","event":"OMERS Infrastructure announced an investment representing approximately 24% of Puget Holdings.","category":"FINANCING","sortDate":"2018-08-01"},{"date":"Aug 8, 2018","event":"AIMCo and BCI increased their Puget Holdings positions and OMERS acquired an initial stake as the consortium acquired predecessor infrastructure-fund interests.","category":"ACQUISITION","sortDate":"2018-08-08"},{"date":"Feb 22, 2022","event":"Macquarie Asset Management and Ontario Teachers' (OTPP) completed the acquisition of a 31.6% stake in Puget Holdings.","category":"ACQUISITION","sortDate":"2022-02-22"},{"date":"Sep 4, 2025","event":"BCI published an investment insight describing Puget Sound Energy as one of BCI's largest and longest-standing infrastructure investments.","category":"OTHER","sortDate":"2025-09-04"}],"management":[],"sources":[{"label":"Pse — Puget Sound Energy","url":"https://www.pse.com/en/about-us","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Close date source — OTPP — Puget Sound Energy","url":"https://www.otpp.com/en-ca/about-us/news-and-insights/2022/macquarie-asset-management-and-ontario-teachers--complete-acquis/","type":"WEBSITE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Pse — Puget Sound Energy","url":"https://www.pse.com/en/Customer-Service/pse-locations-2","type":"ARTICLE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null},{"label":"Omers — Puget Sound Energy","url":"https://www.omers.com/news/omers-infrastructure-announces-investment-in-puget-sound-energy","type":"ARTICLE","purpose":"SUPPORTING_CONTEXT","evidenceLabel":null},{"label":"Close date source — AIMCo — Puget Sound Energy","url":"https://www.sec.gov/Archives/edgar/data/81100/000119312509027209/dex991.htm","type":"SEC_FILING","purpose":"FINANCING_FILINGS","evidenceLabel":null},{"label":"Close date source — BCI — Puget Sound Energy","url":"https://www.sec.gov/Archives/edgar/data/81100/000119312509027209/dex991.htm","type":"SEC_FILING","purpose":"FINANCING_FILINGS","evidenceLabel":null},{"label":"Close date source — Macquarie Asset Management — Puget Sound Energy","url":"https://www.macquarie.com/us/en/about/news/2022/macquarie-asset-management-and-ontario-teachers-complete-acquisition-of-stake-in-puget-holdings.html","type":"WEBSITE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Current investment source — BCI — Puget Sound Energy","url":"https://www.bci.ca/powering-the-pacific-northwest-bcis-strategic-investment-in-puget-sound-energy/","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 2009 initial investment and continuing PSE ownership context"},{"label":"Ownership interest source — BCI I&RR 2024 financial statements — Puget Sound Energy","url":"https://www.bci.ca/wp-content/uploads/2024/08/IRR-Program-FS-2024_Secured.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 20.9% ownership interest in Puget Sound Energy as of December 31, 2024"}]},{"name":"Cleco Corporate Holdings LLC","sector":"UTILITIES","subsector":"Regulated electric utility and wholesale generation","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Cleco Corporate Holdings LLC is part of the privately held Cleco Group utility platform serving Louisiana through Cleco Power and related generation assets. Cleco serves approximately 298,000 residential, commercial, and industrial customers in 24 Louisiana parishes, owns eight generating units with 2,676 MW of rated capacity, and remains regulated by the Louisiana Public Service Commission. The business is asset-heavy and largely regulated, with earnings supported by utility networks, generation assets, and approved tariffs. A North American investor group led by Macquarie Infrastructure and Real Assets and BCI completed the take-private acquisition in April 2016. On April 27, 2026, Stonepeak and Bernhard Capital Partners announced an agreement to acquire Cleco from Macquarie Asset Management, BCI, and Manulife Investment Management, but the transaction remained subject to customary regulatory approvals as of May 12, 2026, so the BCI holding remains active until a closing is confirmed.","companyStatus":"ACTIVE","website":"https://www.cleco.com/","yearFounded":1933,"headquarters":"Pineville, Louisiana","owners":[{"investmentFirm":"Macquarie Asset Management","ownershipVehicle":"n.a.","investmentYear":2016,"status":"Active"},{"investmentFirm":"Manulife Investment Management","ownershipVehicle":"Cleco investor consortium","investmentYear":2016,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2016,"stake":"36.9%","status":"Active"}],"milestones":[{"date":"1933","event":"Cleco's corporate history materials trace the company's founding to 1933.","category":"OTHER","sortDate":"1933-01-01"},{"date":"1933","event":"Cleco Corporate Holdings LLC was founded.","category":"FOUNDING","sortDate":"1933-01-01"},{"date":"Oct 20, 2014","event":"Cleco announced an agreement to be acquired by an investor group led by Macquarie Infrastructure and Real Assets and BCI.","category":"ACQUISITION","sortDate":"2014-10-20"},{"date":"2016","event":"Louisiana regulatory materials disclosed the post-closing ownership interests of Macquarie, BCI, and John Hancock Financial.","category":"FINANCING","sortDate":"2016-01-01"},{"date":"Apr 13, 2016","event":"The investor group completed the acquisition of Cleco.","category":"ACQUISITION","sortDate":"2016-04-13"},{"date":"Apr 27, 2026","event":"Macquarie Asset Management, BCI, and Manulife Investment Management announced an agreement to sell Cleco Group to Stonepeak and Bernhard Capital Partners, subject to regulatory approvals.","category":"DIVESTITURE","sortDate":"2026-04-27"}],"management":[{"name":"William \"Bill\" Fontenot","title":"President and Chief Executive Officer"},{"name":"Kristin Guillory","title":"Chief Financial Officer"},{"name":"Robert Breedlove","title":"Chief Operations Officer"},{"name":"Justin \"Shane\" Hilton","title":"Chief Commercial Officer"},{"name":"Sybil Montegut","title":"Chief Administrative & Sustainability Officer"},{"name":"Andre Guillory","title":"Chief Customer Officer"}],"sources":[{"label":"Company profile source — Cleco Corporate Holdings LLC","url":"https://www.cleco.com/about/history","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Management source — Cleco Corporate Holdings LLC","url":"https://www.cleco.com/about/leadership-governance/executive-officers","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Current Cleco executive officers"},{"label":"Announcement date source — BCI — Cleco Corporate Holdings LLC","url":"https://www.cleco.com/media/press-releases/detail/2014/10/20/cleco-enters-agreement-to-be-acquired-by-north-american-investor-group-led-by-macquarie-infrastructure-and-real-assets-and-british-columbia-investment-management-corporation","type":"PRESS_RELEASE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Close date source — BCI — Cleco Corporate Holdings LLC","url":"https://www.cleco.com/media/press-releases/detail/2016/04/13/north-american-led-investor-group-completes-acquisition-of-cleco","type":"ARTICLE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null},{"label":"Ownership interest source — BCI I&RR 2024 financial statements — Cleco Corporate Holdings LLC","url":"https://www.bci.ca/wp-content/uploads/2024/08/IRR-Program-FS-2024_Secured.pdf","type":"PRESENTATION","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 36.9% ownership interest in Cleco Corporation as of December 31, 2024"},{"label":"Regulatory ownership source — Cleco Corporate Holdings LLC","url":"https://lpscpubvalence.lpsc.louisiana.gov/portal/PSC/ViewFile?fileId=SnuJItgVr6k%3D","type":"ARTICLE","purpose":"FINANCING_FILINGS","evidenceLabel":null},{"label":"Pending sale source — Cleco Corporate Holdings LLC","url":"https://www.cleco.com/media/press-releases/detail/2026/04/27/stonepeak-and-bernhard-capital-partners-to-acquire-cleco","type":"PRESS_RELEASE","purpose":"MILESTONE_EVENT","evidenceLabel":"Sale announced April 27, 2026; subject to regulatory approvals"}]},{"name":"GCT Global Container Terminals","sector":"TRANSPORTATION","subsector":"Container terminal operations","region":"NORTH_AMERICA","country":"Canada","countryTags":["Canada"],"description":"GCT Global Container Terminals operates container terminals on Canada's west coast. Its customers are shipping lines, logistics providers, and cargo owners that rely on marine terminal infrastructure for import, export, and intermodal flows. The operating model is asset-heavy and concession-like, centered on long-life terminal infrastructure and throughput volumes. Current company materials identify GCT as the largest majority Canadian-owned container terminal operator serving the Port of Vancouver, with GCT Deltaport in Delta and GCT Vanterm in Vancouver. Ontario Teachers' remains a current investor, and the last publicly disclosed ownership structure was Ontario Teachers' 37.5%, IFM 37.5%, and BCI 25%.","companyStatus":"ACTIVE","website":null,"yearFounded":1907,"headquarters":"British Columbia","owners":[{"investmentFirm":"OTPP","ownershipVehicle":"n.a.","investmentYear":2007,"stake":"37.5%","status":"Active"},{"investmentFirm":"IFM Investors","ownershipVehicle":"IFM Global Infrastructure Fund (GIF)","investmentYear":2018,"stake":"37.5%","status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2018,"stake":"25%","status":"Active"}],"milestones":[{"date":"1907","event":"GCT states that it has operated on the Vancouver waterfront since 1907.","category":"OTHER","sortDate":"1907-01-01"},{"date":"1907","event":"GCT Global Container Terminals was founded.","category":"FOUNDING","sortDate":"1907-01-01"},{"date":"Jun 2007","event":"OTPP / Ontario Teachers' acquired GCT, then known as Orient Overseas International's terminal business, for approximately US$2.35 billion.","category":"ACQUISITION","sortDate":"2007-06-01"},{"date":"Dec 2018","event":"IFM Investors' portfolio page lists December 2018 as the initial fund investment in GCT after the June 2018 transaction announcement.","category":"ACQUISITION","sortDate":"2018-12-01"},{"date":"2019","event":"The company disclosed an ownership split of 37.5% Ontario Teachers', 37.5% IFM, and 25% BCI.","category":"OTHER","sortDate":"2019-01-01"}],"management":[],"sources":[{"label":"Globalterminals — GCT Global Container Terminals","url":"https://globalterminals.com/about/about-us/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":null},{"label":"Management source — GCT Global Container Terminals","url":"https://globalterminals.com/about/leadership/","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Current GCT leadership team"},{"label":"Announcement date source — IFM Investors / BCI — GCT Global Container Terminals","url":"https://globalterminals.com/ifm-investors-bci-join-ontario-teachers-equity-partners-gct-global-container-terminals-inc/","type":"PRESS_RELEASE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"BCI 25%, IFM 37.5%, Ontario Teachers' 37.5%"},{"label":"Initial fund investment source — IFM Investors — GCT Global Container Terminals","url":"https://www.ifminvestors.com/en-gb/capabilities/infrastructure/our-portfolio/gct-global-container-terminals/","type":"WEBSITE","purpose":"OPERATIONS_ASSETS","evidenceLabel":null},{"label":"Investment date source — OTPP — GCT Global Container Terminals","url":"https://www.otpp.com/en-ca/investments/our-advantage/our-performance-and-track-record/major-investments/","type":"WEBSITE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":null}]},{"name":"Consolidated Communications","sector":"DIGITAL","subsector":"Fiber broadband and enterprise connectivity","region":"NORTH_AMERICA","country":"United States","countryTags":["United States"],"description":"Consolidated Communications, now operating under the Fidium brand, provides fiber broadband, enterprise connectivity, voice, wholesale transport, and related communications services across the United States. Its customers include residential subscribers, small and mid-sized businesses, enterprise customers, government, education, wholesale, and carrier users. The operating model is an asset-heavy telecom network model built on owned and leased fiber and local access infrastructure. Current public materials describe Fidium as a fiber-first internet and network-services company with one of the nation's top fiber networks, approximately 67,000 fiber route miles, more than 700 communities served, and a footprint spanning more than 20 states. Searchlight Capital Partners and BCI completed the take-private acquisition on December 27, 2024. Fidium announced a unified rebrand on September 22, 2025 and noted an inaugural ABS financing exceeding $1 billion to help fund continued fiber expansion.","companyStatus":"ACTIVE","website":"https://www.fidiumfiber.com/","yearFounded":null,"headquarters":"Conroe, Texas; Mattoon, Illinois","owners":[{"investmentFirm":"Searchlight","ownershipVehicle":"n.a.","investmentYear":2024,"status":"Active"},{"investmentFirm":"BCI","ownershipVehicle":"Infrastructure & Renewable Resources","investmentYear":2024,"status":"Active"}],"milestones":[{"date":"Oct 2023","event":"Consolidated announced an agreement to be acquired by Searchlight Capital Partners and BCI.","category":"ACQUISITION","sortDate":"2023-10-01"},{"date":"2024","event":"Regulatory approvals were secured for the take-private transaction.","category":"ACQUISITION","sortDate":"2024-01-01"},{"date":"Jan 2024","event":"Shareholders approved the proposed transaction.","category":"EXPANSION","sortDate":"2024-01-01"},{"date":"Dec 27, 2024","event":"Searchlight and BCI completed the take-private acquisition of Consolidated Communications.","category":"ACQUISITION","sortDate":"2024-12-27"},{"date":"Sep 17, 2025","event":"Consolidated announced a planned CEO transition, with Gaurav Juneja to become CEO at the beginning of 2026.","category":"MANAGEMENT","sortDate":"2025-09-17"},{"date":"Sep 22, 2025","event":"Consolidated Communications announced that its residential, business, and wholesale lines of business would unite under the Fidium brand.","category":"OTHER","sortDate":"2025-09-22"},{"date":"Sep 22, 2025","event":"Fidium disclosed an inaugural ABS financing exceeding $1 billion to help fuel continued fiber expansion.","category":"FINANCING","sortDate":"2025-09-22"}],"management":[{"name":"Gaurav Juneja","title":"President and Chief Executive Officer"},{"name":"Fred Graffam","title":"Executive Vice President and Chief Financial Officer"},{"name":"Dan Stoll","title":"President of Commercial and Carrier"}],"sources":[{"label":"Consolidated — Consolidated Communications","url":"https://www.consolidated.com/About-Us/News/Article-Detail/ID/979/Consolidated-Communications-Announces-Agreement-to-be-Acquired-by-Searchlight-Capital-Partners-and-British-Columbia-Investment-Management-Corporation","type":"WEBSITE","purpose":"MILESTONE_EVENT","evidenceLabel":null},{"label":"Searchlightcap — Consolidated Communications","url":"https://searchlightcap.com/news/consolidated-communications-shareholders-approve-proposed-transaction-with-searchlight-and-bci/","type":"ARTICLE","purpose":"SUPPORTING_CONTEXT","evidenceLabel":null},{"label":"SEC — Consolidated Communications","url":"https://www.sec.gov/Archives/edgar/data/1304421/000110465923109249/tm2328485d2_defa14a.htm","type":"SEC_FILING","purpose":"FINANCING_FILINGS","evidenceLabel":null},{"label":"Broadbandbreakfast — Consolidated Communications","url":"https://broadbandbreakfast.com/fcc-approves-sale-of-consolidated-communications-to-pe-firms/","type":"ARTICLE","purpose":"MILESTONE_EVENT","evidenceLabel":null},{"label":"Close date source — Searchlight / BCI — Consolidated Communications","url":"https://www.consolidated.com/About-Us/Investor-Relations","type":"WEBSITE","purpose":"OWNERSHIP_INVESTMENT","evidenceLabel":"December 27, 2024 completion by Searchlight affiliates and BCI"},{"label":"Company profile and rebrand source — Fidium","url":"https://www.fidiumfiber.com/blog/news/consolidated-communications-becomes-fidium-uniting-all-services-under-one-bold-identity","type":"PRESS_RELEASE","purpose":"COMPANY_PROFILE","evidenceLabel":"Fidium rebrand, fiber footprint, ABS financing, and incoming CEO"},{"label":"Management source — Consolidated Communications","url":"https://www.consolidated.com/about-us/news/article-detail/id/1118/consolidated-communications-announces-ceo-transition","type":"PRESS_RELEASE","purpose":"MILESTONE_EVENT","evidenceLabel":"Gaurav Juneja promoted to CEO at the beginning of 2026"},{"label":"Management source — Consolidated Communications leadership","url":"https://www.consolidated.com/About-Us/leadership/michael-smith","type":"WEBSITE","purpose":"COMPANY_PROFILE","evidenceLabel":"Executive leadership roster"}]}]$payload$::jsonb;
  company_record jsonb;
  owner_record jsonb;
  milestone_record jsonb;
  management_record jsonb;
  source_record jsonb;
  company_id text;
  org_id text;
  person_id text;
  source_id text;
  row_index integer;
BEGIN
  FOR company_record IN SELECT value FROM jsonb_array_elements(payload) AS records(value) LOOP
    INSERT INTO "Company" (
      "id",
      "name",
      "sector",
      "subsector",
      "region",
      "country",
      "countryTags",
      "description",
      "companyStatus",
      "website",
      "yearFounded",
      "headquarters",
      "status",
      "createdAt",
      "updatedAt"
    )
    VALUES (
      'company_bci_' || md5((company_record->>'name') || '|' || (company_record->>'country')),
      company_record->>'name',
      (company_record->>'sector')::"CompanySector",
      company_record->>'subsector',
      (company_record->>'region')::"CompanyRegion",
      company_record->>'country',
      ARRAY(SELECT jsonb_array_elements_text(company_record->'countryTags')),
      company_record->>'description',
      (company_record->>'companyStatus')::"CompanyStatus",
      company_record->>'website',
      CASE
        WHEN company_record->>'yearFounded' IS NULL THEN NULL
        ELSE (company_record->>'yearFounded')::integer
      END,
      company_record->>'headquarters',
      'PUBLISHED',
      now(),
      now()
    )
    ON CONFLICT ("name", "country") DO UPDATE SET
      "sector" = EXCLUDED."sector",
      "subsector" = EXCLUDED."subsector",
      "region" = EXCLUDED."region",
      "countryTags" = EXCLUDED."countryTags",
      "description" = EXCLUDED."description",
      "companyStatus" = EXCLUDED."companyStatus",
      "website" = EXCLUDED."website",
      "yearFounded" = EXCLUDED."yearFounded",
      "headquarters" = EXCLUDED."headquarters",
      "status" = 'PUBLISHED',
      "updatedAt" = now()
    RETURNING "id" INTO company_id;

    DELETE FROM "OwnershipPeriod"
    WHERE "companyId" = company_id;

    FOR owner_record IN SELECT value FROM jsonb_array_elements(company_record->'owners') AS records(value) LOOP
      INSERT INTO "Organization" ("id", "name", "types", "status", "createdAt", "updatedAt")
      VALUES (
        'org_bci_' || md5(owner_record->>'investmentFirm'),
        owner_record->>'investmentFirm',
        ARRAY['FUND_MANAGER']::"OrgType"[],
        'PUBLISHED',
        now(),
        now()
      )
      ON CONFLICT ("name") DO NOTHING;

      SELECT "id" INTO org_id
      FROM "Organization"
      WHERE "name" = owner_record->>'investmentFirm'
      LIMIT 1;

      INSERT INTO "OwnershipPeriod" (
        "id",
        "companyId",
        "organizationId",
        "fundId",
        "vehicleName",
        "stake",
        "investmentYear",
        "exitYear",
        "isActive",
        "createdAt"
      )
      VALUES (
        'ownership_bci_' || md5(company_id || '|' || org_id || '|' || COALESCE(owner_record->>'ownershipVehicle', '')),
        company_id,
        org_id,
        (SELECT "id" FROM "Fund" WHERE "fundName" = owner_record->>'ownershipVehicle' LIMIT 1),
        owner_record->>'ownershipVehicle',
        owner_record->>'stake',
        CASE
          WHEN owner_record->>'investmentYear' IS NULL THEN NULL
          ELSE (owner_record->>'investmentYear')::integer
        END,
        CASE
          WHEN owner_record->>'exitYear' IS NULL THEN NULL
          ELSE (owner_record->>'exitYear')::integer
        END,
        COALESCE(owner_record->>'status', 'Active') = 'Active',
        now()
      )
      ON CONFLICT ("companyId", "organizationId", "vehicleName") DO UPDATE SET
        "fundId" = EXCLUDED."fundId",
        "stake" = EXCLUDED."stake",
        "investmentYear" = EXCLUDED."investmentYear",
        "exitYear" = EXCLUDED."exitYear",
        "isActive" = EXCLUDED."isActive";
    END LOOP;

    DELETE FROM "Milestone"
    WHERE "companyId" = company_id;

    row_index := 0;
    FOR milestone_record IN SELECT value FROM jsonb_array_elements(company_record->'milestones') AS records(value) LOOP
      row_index := row_index + 1;
      INSERT INTO "Milestone" ("id", "companyId", "date", "event", "category", "sortDate")
      VALUES (
        'milestone_bci_' || md5(company_id || '|' || row_index::text),
        company_id,
        milestone_record->>'date',
        milestone_record->>'event',
        (milestone_record->>'category')::"MilestoneCategory",
        CASE
          WHEN milestone_record->>'sortDate' IS NULL THEN NULL
          ELSE (milestone_record->>'sortDate')::timestamp
        END
      )
      ON CONFLICT ("id") DO UPDATE SET
        "date" = EXCLUDED."date",
        "event" = EXCLUDED."event",
        "category" = EXCLUDED."category",
        "sortDate" = EXCLUDED."sortDate";
    END LOOP;

    DELETE FROM "ManagementRole"
    WHERE "companyId" = company_id;

    FOR management_record IN SELECT value FROM jsonb_array_elements(company_record->'management') AS records(value) LOOP
      SELECT "id" INTO person_id
      FROM "Person"
      WHERE "name" = management_record->>'name'
      ORDER BY "id"
      LIMIT 1;

      IF person_id IS NULL THEN
        person_id := 'person_bci_' || md5(management_record->>'name');
        INSERT INTO "Person" ("id", "name")
        VALUES (person_id, management_record->>'name')
        ON CONFLICT ("id") DO UPDATE SET
          "name" = EXCLUDED."name";
      END IF;

      INSERT INTO "ManagementRole" ("id", "personId", "companyId", "title")
      VALUES (
        'role_bci_' || md5(company_id || '|' || person_id || '|' || (management_record->>'title')),
        person_id,
        company_id,
        management_record->>'title'
      )
      ON CONFLICT ("id") DO UPDATE SET
        "personId" = EXCLUDED."personId",
        "companyId" = EXCLUDED."companyId",
        "title" = EXCLUDED."title";
    END LOOP;

    DELETE FROM "Citation"
    WHERE "companyId" = company_id;

    FOR source_record IN SELECT value FROM jsonb_array_elements(company_record->'sources') AS records(value) LOOP
      INSERT INTO "Source" ("id", "label", "url", "type", "createdAt")
      VALUES (
        'source_bci_' || md5(source_record->>'url'),
        source_record->>'label',
        source_record->>'url',
        (source_record->>'type')::"SourceType",
        now()
      )
      ON CONFLICT ("url") DO UPDATE SET
        "label" = EXCLUDED."label",
        "type" = EXCLUDED."type"
      RETURNING "id" INTO source_id;

      INSERT INTO "Citation" ("id", "sourceId", "companyId", "purpose", "evidenceLabel")
      VALUES (
        'citation_bci_' || md5(company_id || '|' || (source_record->>'url') || '|' || (source_record->>'purpose') || '|' || (source_record->>'label')),
        source_id,
        company_id,
        (source_record->>'purpose')::"CitationPurpose",
        COALESCE(source_record->>'evidenceLabel', source_record->>'label')
      )
      ON CONFLICT ("id") DO UPDATE SET
        "sourceId" = EXCLUDED."sourceId",
        "companyId" = EXCLUDED."companyId",
        "purpose" = EXCLUDED."purpose",
        "evidenceLabel" = EXCLUDED."evidenceLabel";
    END LOOP;
  END LOOP;
END $migration$;
